+            "hooks": {
+                "PreToolUse": [
+                    {
+                        "matcher": "Bash",
+                        "hooks": [
+                            {
+                                "type": "command",
+                                "command": "rch"
+                            }
+                        ]
+                    }
+                ]
+            }
+        }));
+
+        // Action: install hook (should detect already installed)
+        let result = install_hook(AgentKind::ClaudeCode, false);
+        eprintln!("  Result: {:?}", result);
