+
+        // Action: install hook
+        let result = install_hook(AgentKind::ClaudeCode, false);
+        eprintln!("  Result: {:?}", result);
+
+        // The current implementation silently replaces invalid JSON with {}
+        // This is a reasonable behavior - let's just verify it doesn't crash
